  1000→// =============== MOCK INTERVIEW SESSIONS (Dynamic AI Interviewer) ===============
  1001→
  1002→// Helper: hash JD for dedup
  1003→function hashJD(text) {
  1004→  if (!text) return null;
  1005→  return crypto.createHash('sha256').update(text.trim().toLowerCase()).digest('hex').substring(0, 16);
  1006→}
  1007→
  1008→// Start a mock interview session — generates or pulls questions for the role
  1009→router.post('/mock/start', authMiddleware, async (req, res) => {
  1010→  try {
  1011→    const { target_role, job_description } = req.body;
  1012→
  1013→    if (!target_role || target_role.trim().length < 2) {
  1014→      return res.status(400).json({ error: 'Please enter a target role (e.g., "Software Engineer", "Product Manager")' });
  1015→    }
  1016→
  1017→    const role = target_role.trim();
  1018→    const jdHash = hashJD(job_description);
  1019→
  1020→    // Check if we already have questions in the bank for this role/JD combo
  1021→    let bankQuestions;
  1022→    const existing = await pool.query(
  1023→      `SELECT * FROM question_bank WHERE LOWER(role) = LOWER($1) ${jdHash ? 'AND jd_hash = $2' : 'AND jd_hash IS NULL'}
  1024→       ORDER BY RANDOM()`,
  1025→      jdHash ? [role, jdHash] : [role]
  1026→    );
  1027→
  1028→    if (existing.rows.length >= 8) {
  1029→      // Use existing bank — pick random 8-10
  1030→      bankQuestions = existing.rows.slice(0, Math.min(10, existing.rows.length));
  1031→      console.log(`[mock] Found ${existing.rows.length} existing questions for "${role}", using ${bankQuestions.length}`);
  1032→    } else {
  1033→      // Generate new question bank
  1034→      console.log(`[mock] Generating new question bank for "${role}"...`);
  1035→      const generated = await generateQuestionBank(role, job_description, {
  1036→        subscriptionId: req.user.stripe_subscription_id
  1037→      });
  1038→
  1039→      if (!generated || !Array.isArray(generated) || generated.length === 0) {
  1040→        return res.status(500).json({ error: 'Failed to generate questions. Please try again.' });
  1041→      }
  1042→
  1043→      // Store in question_bank
  1044→      const insertedIds = [];
  1045→      for (const q of generated) {
  1046→        try {
  1047→          const result = await pool.query(
  1048→            `INSERT INTO question_bank (role, jd_hash, skills, question_text, question_type, difficulty, key_points)
  1049→             VALUES ($1, $2, $3, $4, $5, $6, $7)
  1050→             RETURNING id`,
  1051→            [
  1052→              role,
  1053→              jdHash,
  1054→              q.skills_tested || [],
  1055→              q.question_text,
  1056→              q.question_type || 'behavioral',
  1057→              q.difficulty || 'medium',
  1058→              q.key_points || []
  1059→            ]
  1060→          );
  1061→          insertedIds.push(result.rows[0].id);
  1062→        } catch (insertErr) {
  1063→          console.error('[mock] Failed to insert question:', insertErr.message);
  1064→        }
  1065→      }
  1066→
  1067→      console.log(`[mock] Stored ${insertedIds.length} questions in bank`);
  1068→
  1069→      // Pull 8-10 random from what we just inserted
  1070→      const freshQuestions = await pool.query(
  1071→        `SELECT * FROM question_bank WHERE id = ANY($1) ORDER BY RANDOM() LIMIT 10`,
  1072→        [insertedIds]
  1073→      );
  1074→      bankQuestions = freshQuestions.rows;
  1075→    }
  1076→
  1077→    if (!bankQuestions || bankQuestions.length === 0) {
  1078→      return res.status(500).json({ error: 'No questions available. Please try again.' });
  1079→    }
  1080→
  1081→    // Create mock interview session
  1082→    const questionIds = bankQuestions.map(q => q.id);
  1083→
  1084→    // Build opening message from the AI interviewer
  1085→    const openingMessage = {
  1086→      role: 'interviewer',
  1087→      text: `Hi! Thanks for joining this mock interview for the ${role} position. I'll be asking you a series of questions to assess your fit. Take your time with each answer — I may ask follow-ups based on what you share. Let's get started.\n\n${bankQuestions[0].question_text}`,
  1088→      action: 'transition',
  1089→      timestamp: new Date().toISOString()
  1090→    };
  1091→
  1092→    const session = await pool.query(
  1093→      `INSERT INTO mock_interview_sessions
  1094→       (user_id, target_role, job_description, jd_hash, question_ids, conversation, current_question_index, questions_asked)
  1095→       VALUES ($1, $2, $3, $4, $5, $6, 1, 1)
  1096→       RETURNING *`,
  1097→      [
  1098→        req.user.id,
  1099→        role,
  1100→        job_description || null,
  1101→        jdHash,
  1102→        questionIds,
  1103→        JSON.stringify([openingMessage])
  1104→      ]
  1105→    );
  1106→
  1107→    // Increment times_used for first question
  1108→    await pool.query('UPDATE question_bank SET times_used = times_used + 1 WHERE id = $1', [bankQuestions[0].id]);
  1109→
  1110→    res.json({
  1111→      success: true,
  1112→      session: session.rows[0],
  1113→      questions_count: bankQuestions.length,
  1114→      first_message: openingMessage
  1115→    });
  1116→  } catch (err) {
  1117→    console.error('Start mock interview error:', err);
  1118→    res.status(500).json({ error: 'Failed to start mock interview' });
  1119→  }
  1120→});
