  1122→// Submit a response in a mock interview — AI responds conversationally
  1123→router.post('/mock/:sessionId/respond', authMiddleware, async (req, res) => {
  1124→  try {
  1125→    const { response_text } = req.body;
  1126→    const sessionId = req.params.sessionId;
  1127→
  1128→    if (!response_text || response_text.trim().length < 10) {
  1129→      return res.status(400).json({ error: 'Response too short. Please elaborate on your answer.' });
  1130→    }
  1131→
  1132→    // Get session
  1133→    const sessionResult = await pool.query(
  1134→      'SELECT * FROM mock_interview_sessions WHERE id = $1 AND user_id = $2 AND status = $3',
  1135→      [sessionId, req.user.id, 'in_progress']
  1136→    );
  1137→
  1138→    if (sessionResult.rows.length === 0) {
  1139→      return res.status(404).json({ error: 'Session not found or already completed' });
  1140→    }
  1141→
  1142→    const session = sessionResult.rows[0];
  1143→    const conversation = session.conversation || [];
  1144→    const questionIds = session.question_ids || [];
  1145→
  1146→    // Get base questions from bank
  1147→    const questionsResult = await pool.query(
  1148→      'SELECT * FROM question_bank WHERE id = ANY($1)',
  1149→      [questionIds]
  1150→    );
  1151→    // Maintain order from questionIds
  1152→    const questionMap = {};
  1153→    questionsResult.rows.forEach(q => { questionMap[q.id] = q; });
  1154→    const baseQuestions = questionIds.map(id => questionMap[id]).filter(Boolean);
  1155→
  1156→    // Add candidate response to conversation
  1157→    const candidateMessage = {
  1158→      role: 'candidate',
  1159→      text: response_text.trim(),
  1160→      timestamp: new Date().toISOString()
  1161→    };
  1162→    conversation.push(candidateMessage);
  1163→
  1164→    // AI generates next interviewer turn
  1165→    const aiTurn = await conductInterviewTurn(
  1166→      conversation,
  1167→      baseQuestions,
  1168→      session.current_question_index,
  1169→      session.target_role,
  1170→      { subscriptionId: req.user.stripe_subscription_id }
  1171→    );
  1172→
  1173→    // Build interviewer message
  1174→    let interviewerText = aiTurn.reaction || '';
  1175→    if (aiTurn.question) {
  1176→      interviewerText += (interviewerText ? '\n\n' : '') + aiTurn.question;
  1177→    }
  1178→
  1179→    const interviewerMessage = {
  1180→      role: 'interviewer',
  1181→      text: interviewerText,
  1182→      action: aiTurn.action || 'transition',
  1183→      score_hint: aiTurn.score_hint || null,
  1184→      notes: aiTurn.notes || null,
  1185→      timestamp: new Date().toISOString()
  1186→    };
  1187→    conversation.push(interviewerMessage);
  1188→
  1189→    // Update session
  1190→    const isWrappingUp = aiTurn.action === 'wrap_up';
  1191→    const isTransition = aiTurn.action === 'transition';
  1192→    const newQuestionIndex = isTransition
  1193→      ? Math.min(session.current_question_index + 1, baseQuestions.length)
  1194→      : session.current_question_index;
  1195→    const newFollowUps = (aiTurn.action === 'follow_up' || aiTurn.action === 'challenge')
  1196→      ? (session.follow_ups_asked || 0) + 1
  1197→      : session.follow_ups_asked || 0;
  1198→
  1199→    // Increment times_used for the new question if transitioning
  1200→    if (isTransition && newQuestionIndex < baseQuestions.length) {
  1201→      const nextQ = baseQuestions[newQuestionIndex];
  1202→      if (nextQ) {
  1203→        await pool.query('UPDATE question_bank SET times_used = times_used + 1 WHERE id = $1', [nextQ.id]);
  1204→      }
  1205→    }
  1206→
  1207→    await pool.query(
  1208→      `UPDATE mock_interview_sessions
  1209→       SET conversation = $1, current_question_index = $2,
  1210→           questions_asked = $3, follow_ups_asked = $4
  1211→       WHERE id = $5`,
  1212→      [
  1213→        JSON.stringify(conversation),
  1214→        newQuestionIndex,
  1215→        isTransition ? (session.questions_asked || 0) + 1 : session.questions_asked || 0,
  1216→        newFollowUps,
  1217→        sessionId
  1218→      ]
  1219→    );
  1220→
  1221→    res.json({
  1222→      success: true,
  1223→      interviewer_message: interviewerMessage,
  1224→      action: aiTurn.action,
  1225→      questions_asked: isTransition ? (session.questions_asked || 0) + 1 : session.questions_asked || 0,
  1226→      is_wrapping_up: isWrappingUp
  1227→    });
  1228→  } catch (err) {
  1229→    console.error('Mock interview respond error:', err);
  1230→    res.status(500).json({ error: 'Failed to process response. Please try again.' });
  1231→  }
  1232→});
