   575→// Select evenly-spaced key frames from a larger set
   576→function selectKeyFrames(frames, count) {
   577→  const result = [];
   578→  const step = (frames.length - 1) / (count - 1);
   579→  for (let i = 0; i < count; i++) {
   580→    result.push(frames[Math.round(i * step)]);
   581→  }
   582→  return result;
   583→}
