      method: 'POST',
      headers: {
        'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
        ...formData.getHeaders()
      },
      body: formData
    });

    const result = await uploadRes.json();

    if (!result.success) {
      console.error('R2 upload error:', result.error);
      return res.status(500).json({ error: 'Failed to upload video' });
    }

    res.json({
      success: true,
